import { v } from "convex/values";
import { query, mutation, internalMutation, internalAction } from "./_generated/server";
import { Id } from "./_generated/dataModel";

/**
 * K-1 Records Table - Handles K-1 Pass-Through Syncing
 * 
 * This module manages K-1 data generated by partnerships (Form 1065) and 
 * S-Corporations (Form 1120S) and syncs it to individual owners' 1040 returns.
 * 
 * K-1 data flows through:
 * Business Return (1065/1120S) -> K-1 Records -> Individual 1040 Return
 */

// =============================================================================
// TYPE DEFINITIONS
// =============================================================================

/**
 * K-1 Data structure containing all K-1 fields
 * form These fields flow from Schedule K-1 (Form 1065 or 1120S) to the recipient's 1040
 */
export interface K1Data {
  // Income items (Box 1-7)
  ordinaryBusinessIncome?: number;
  qualifiedBusinessIncome?: number;
  section199ADeduction?: number;
  
  // Box 8 - Specific Deductions
  charitableContributions?: number;
  investmentInterest?: number;
  section179Deduction?: number;
  otherDeductions?: number;
  
  // Box 9 - Tax Exempt Income
  taxExemptInterest?: number;
  exemptQualifiedDividends?: number;
  
  // Box 10 - Credits
  foreignTaxCredit?: number;
  otherCredits?: number;
  
  // Box 11 - Other Items
  ordinaryDividends?: number;
  qualifiedDividends?: number;
  section409ATaxDeferral?: number;
  otherItems?: number;
  
  // Box 12 - Supplemental Information
  section199AQualifiedBusinessIncome?: number;
  section199AQualifiedProperty?: number;
  section199AWages?: number;
  
  // Additional K-1 fields
  selfEmploymentEarnings?: number;
  selfEmploymentDeductions?: number;
  healthInsurance?: number;
  sepSIMPLE?: number;
  qualifiedPlanExpenses?: number;
  
  // Investment items
  interestIncome?: number;
  shortTermCapitalGains?: number;
  longTermCapitalGains?: number;
  section1231Gains?: number;
  section1231Losses?: number;
  
  // Rental real estate
  rentalRealEstateIncome?: number;
  rentalRealEstateExpenses?: number;
  
  // Other income/expenses
  otherIncome?: number;
  otherExpenses?: number;
}

export type SyncStatus = "pending" | "synced" | "error";

// =============================================================================
// QUERY FUNCTIONS
// =============================================================================

/**
 * Get a specific K-1 record by ID
 */
export const getK1Record = query({
  args: { id: v.id("k1Records") },
  handler: async (ctx, args) => {
    return await ctx.db.get(args.id);
  },
});

/**
 * Get all K-1 records for a business return (1065/1120S)
 */
export const getK1RecordsByReturn = query({
  args: { returnId: v.id("returns") },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("k1Records")
      .withIndex("by_return", (q) => q.eq("returnId", args.returnId))
      .collect();
  },
});

/**
 * Get all K-1 records for a specific partner/owner
 */
export const getK1RecordsByPartner = query({
  args: { partnerId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("k1Records")
      .withIndex("by_partnerId", (q) => q.eq("partnerId", args.partnerId))
      .collect();
  },
});

/**
 * Get K-1 records filtered by sync status (pending, synced, error)
 */
export const getK1RecordsByStatus = query({
  args: { syncStatus: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("k1Records")
      .withIndex("by_syncStatus", (q) => q.eq("syncStatus", args.syncStatus))
      .collect();
  },
});

/**
 * Get all K-1 records that need to be synced
 */
export const getPendingK1Sync = query({
  args: {},
  handler: async (ctx) => {
    return await ctx.db
      .query("k1Records")
      .withIndex("by_syncStatus", (q) => q.eq("syncStatus", "pending"))
      .collect();
  },
});

/**
 * List all K-1 records with pagination
 */
export const listK1Records = query({
  args: { 
    limit: v.optional(v.number()),
    cursor: v.optional(v.id("k1Records")),
  },
  handler: async (ctx, args) => {
    const limit = args.limit ?? 50;
    const { cursor } = args;
    
    let query = ctx.db.query("k1Records").order("desc");
    
    if (cursor) {
      // Get the record at the cursor to use as a starting point
      const cursorRecord = await ctx.db.get(cursor);
      if (cursorRecord) {
        query = query.filter((q) => q.lt("_creationTime", cursorRecord._creationTime));
      }
    }
    
    const results = await query.take(limit);
    
    // Determine if there are more results
    const hasMore = results.length === limit;
    const nextCursor = hasMore ? results[results.length - 1]._id : null;
    
    return {
      results,
      hasMore,
      nextCursor,
    };
  },
});

/**
 * Get K-1 record by return and partner combination
 */
export const getK1RecordByReturnAndPartner = query({
  args: { 
    returnId: v.id("returns"), 
    partnerId: v.string() 
  },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("k1Records")
      .withIndex("by_return", (q) => q.eq("returnId", args.returnId))
      .filter((q) => q.eq(q.field("partnerId"), args.partnerId))
      .first();
  },
});

// =============================================================================
// MUTATION FUNCTIONS - CRUD OPERATIONS
// =============================================================================

/**
 * Create a new K-1 record
 * 
 * This is called when:
 * - A partnership return (1065) is processed and K-1s need to be generated
 * - An S-Corporation return (1120S) is processed and K-1s need to be generated
 * - Manual K-1 entry is performed
 */
export const createK1Record = mutation({
  args: {
    returnId: v.id("returns"),
    partnerId: v.string(),
    ein: v.string(),
    recipientName: v.string(),
    recipientTin: v.string(),
    k1Data: v.any(),
    syncStatus: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const now = Date.now();
    
    const k1RecordId = await ctx.db.insert("k1Records", {
      returnId: args.returnId,
      partnerId: args.partnerId,
      ein: args.ein,
      recipientName: args.recipientName,
      recipientTin: args.recipientTin,
      k1Data: args.k1Data,
      syncStatus: args.syncStatus ?? "pending",
      syncedAt: undefined,
      createdAt: now,
    });
    
    return k1RecordId;
  },
});

/**
 * Update an existing K-1 record
 */
export const updateK1Record = mutation({
  args: {
    id: v.id("k1Records"),
    ein: v.optional(v.string()),
    recipientName: v.optional(v.string()),
    recipientTin: v.optional(v.string()),
    k1Data: v.optional(v.any()),
    syncStatus: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const { id, ...updates } = args;
    
    // Get existing record to check current state
    const existing = await ctx.db.get(id);
    if (!existing) {
      throw new Error(`K-1 record not found: ${id}`);
    }
    
    // Clear syncedAt if status changed from synced
    if (updates.syncStatus && updates.syncStatus !== existing.syncStatus) {
      if (updates.syncStatus === "pending") {
        updates.syncedAt = undefined;
      }
    }
    
    await ctx.db.patch(id, updates);
    
    return { success: true };
  },
});

/**
 * Mark a K-1 record as synced with timestamp
 */
export const markK1Synced = mutation({
  args: { id: v.id("k1Records") },
  handler: async (ctx, args) => {
    const now = Date.now();
    
    await ctx.db.patch(args.id, {
      syncStatus: "synced",
      syncedAt: now,
    });
    
    return { success: true, syncedAt: now };
  },
});

/**
 * Mark a K-1 record as errored
 */
export const markK1Error = mutation({
  args: { 
    id: v.id("k1Records"),
    errorMessage: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.id, {
      syncStatus: "error",
    });
    
    // Note: Could also store error message in k1Data or separate field
    // For now, error details would need to be retrieved from audit logs
    
    return { success: true };
  },
});

/**
 * Delete a K-1 record
 */
export const deleteK1Record = mutation({
  args: { id: v.id("k1Records") },
  handler: async (ctx, args) => {
    await ctx.db.delete(args.id);
    return { success: true };
  },
});

// =============================================================================
// K-1 SYNC FUNCTIONS - CORE BUSINESS LOGIC
// =============================================================================

/**
 * Generate K-1 records for all partners from a 1065 partnership return
 * 
 * This function:
 * 1. Queries the partnership return for partner information
 * 2. Creates K-1 records for each partner
 * 3. Extracts Schedule K-1 data from the 1065 return
 */
export const generateK1FromPartnership = internalMutation({
  args: {
    partnershipReturnId: v.id("returns"),
    userId: v.string(),
  },
  handler: async (ctx, args) => {
    // Get the partnership return
    const partnershipReturn = await ctx.db.get(args.partnershipReturnId);
    if (!partnershipReturn) {
      throw new Error(`Partnership return not found: ${args.partnershipReturnId}`);
    }
    
    // Get all form instances for this return (to find Schedule K-1 data)
    const formInstances = await ctx.db
      .query("formInstances")
      .withIndex("by_return", (q) => q.eq("returnId", args.partnershipReturnId))
      .collect();
    
    // Look for Schedule K-1 form instances
    const k1FormInstances = formInstances.filter(
      (f) => f.formType === "ScheduleK1" || f.formType === "K1"
    );
    
    // For each K-1 form instance, create a K-1 record
    const createdK1Ids: string[] = [];
    
    for (const k1Form of k1FormInstances) {
      // Get all fields for this K-1 form
      const k1Fields = await ctx.db
        .query("fields")
        .withIndex("by_instance", (q) => q.eq("instanceId", k1Form.instanceId))
        .collect();
      
      // Extract K-1 data
      const k1Data: K1Data = {};
      
      for (const field of k1Fields) {
        switch (field.fieldKey) {
          case "ordinaryBusinessIncome":
          case "box1":
            k1Data.ordinaryBusinessIncome = field.value as number;
            break;
          case "qualifiedBusinessIncome":
          case "box2":
            k1Data.qualifiedBusinessIncome = field.value as number;
            break;
          case "section199ADeduction":
          case "box3":
            k1Data.section199ADeduction = field.value as number;
            break;
          case "charitableContributions":
          case "box5a":
            k1Data.charitableContributions = field.value as number;
            break;
          case "investmentInterest":
          case "box5c":
            k1Data.investmentInterest = field.value as number;
            break;
          case "section179Deduction":
          case "box5d":
            k1Data.section179Deduction = field.value as number;
            break;
          case "foreignTaxCredit":
          case "box6":
            k1Data.foreignTaxCredit = field.value as number;
            break;
          case "ordinaryDividends":
          case "box4a":
            k1Data.ordinaryDividends = field.value as number;
            break;
          case "qualifiedDividends":
          case "box4b":
            k1Data.qualifiedDividends = field.value as number;
            break;
          case "box7":
          case "otherDeductions":
            k1Data.otherDeductions = field.value as number;
            break;
          // Partner info stored in instance name or specific fields
          case "partnerName":
            // This would need to be extracted from form
            break;
          case "partnerTin":
            // This would need to be extracted from form
            break;
        }
      }
      
      // Extract partner info from the form instance
      // In a real implementation, this would come from the Schedule K-1 partner info
      const partnerId = k1Form.instanceName || ""; // Would need actual partner ID
      const recipientName = k1Form.instanceName || "Unknown Partner";
      const recipientTin = ""; // Would need to extract from K-1 fields
      const ein = ""; // Would need to extract from K-1 fields
      
      // Create the K-1 record
      const k1Id = await ctx.db.insert("k1Records", {
        returnId: args.partnershipReturnId,
        partnerId,
        ein,
        recipientName,
        recipientTin,
        k1Data,
        syncStatus: "pending",
        createdAt: Date.now(),
      });
      
      createdK1Ids.push(k1Id);
      
      // Log the K-1 generation
      await ctx.db.insert("auditLogs", {
        returnId: args.partnershipReturnId,
        userId: args.userId,
        action: "K-1 Generated",
        fieldKey: k1Form.instanceId,
        previousValue: null,
        newValue: k1Data,
        source: "calculated",
        timestamp: Date.now(),
      });
    }
    
    return {
      success: true,
      createdCount: createdK1Ids.length,
      k1RecordIds: createdK1Ids,
    };
  },
});

