/**
 * Sync a single K-1 record to the partner's 1040 return
 * 
 * This is the core function that:
 * 1. Gets the K-1 record data
 * 2. Finds or creates the appropriate form instances in the 1040 return
 * 3. Maps K-1 fields to 1040 fields (e.g., K-1 ordinary income -> 1040 Schedule E)
 * 4. Updates the individual return with the K-1 data
 * 5. Logs the sync in auditLogs with source "k1_sync"
 */
export const syncK1ToIndividual = internalMutation({
  args: {
    k1RecordId: v.id("k1Records"),
    userId: v.string(),
  },
  handler: async (ctx, args) => {
    // Get the K-1 record
    const k1Record = await ctx.db.get(args.k1RecordId);
    if (!k1Record) {
      throw new Error(`K-1 record not found: ${args.k1RecordId}`);
    }
    
    // Skip if already synced
    if (k1Record.syncStatus === "synced") {
      return { success: true, message: "Already synced" };
    }
    
    const k1Data = k1Record.k1Data as K1Data;
    
    // Get the partner's individual return - partnerId is the individual return ID
    const partnerReturnId = k1Record.partnerId as string;
    const individualReturn = await ctx.db.get(partnerReturnId as Id<"returns">);
    if (!individualReturn) {
      // Mark as error - partner return not found
      await ctx.db.patch(args.k1RecordId, { syncStatus: "error" });
      
      await ctx.db.insert("auditLogs", {
        returnId: k1Record.returnId,
        userId: args.userId,
        action: "K-1 Sync Error",
        previousValue: null,
        newValue: { error: "Partner return not found", partnerId: k1Record.partnerId },
        source: "k1_sync",
        timestamp: Date.now(),
      });
      
      return { success: false, error: "Partner return not found" };
    }
    
    // Find or create Schedule E (Supplemental Income and Loss) for partnership/S-corp income
    let scheduleE = await ctx.db
      .query("formInstances")
      .withIndex("by_return", (q) => q.eq("returnId", partnerReturnId as Id<"returns">))
      .filter((q) => q.eq(q.field("formType"), "ScheduleE"))
      .first();
    
    if (!scheduleE) {
      // Create Schedule E instance
      const instanceId = await ctx.db.insert("formInstances", {
        returnId: partnerReturnId as Id<"returns">,
        formType: "ScheduleE",
        instanceName: "Schedule E - Supplemental Income",
        status: "In Progress",
        documentSource: "calculated",
      });
      scheduleE = await ctx.db.get(instanceId);
    }
    
    // Map K-1 fields to Schedule E fields
    // Part II - Income or Loss from Partnerships and S Corporations
    const scheduleEFields: { fieldKey: string; value: any }[] = [];
    
    // Ordinary business income (Box 1) -> Schedule E Line 2
    if (k1Data.ordinaryBusinessIncome !== undefined) {
      scheduleEFields.push({
        fieldKey: "line2_partnership",
        value: k1Data.ordinaryBusinessIncome,
      });
    }
    
    // Section 199A deduction (Box 3) -> Schedule E Line 2
    if (k1Data.section199ADeduction !== undefined) {
      scheduleEFields.push({
        fieldKey: "line2_section199A",
        value: k1Data.section199ADeduction,
      });
    }
    
    // Charitable contributions -> Schedule E Line 3
    if (k1Data.charitableContributions !== undefined) {
      scheduleEFields.push({
        fieldKey: "line3_charitable",
        value: k1Data.charitableContributions,
      });
    }
    
    // Investment interest -> Schedule E Line 3
    if (k1Data.investmentInterest !== undefined) {
      scheduleEFields.push({
        fieldKey: "line3_investment",
        value: k1Data.investmentInterest,
      });
    }
    
    // Update or create fields in Schedule E
    for (const fieldUpdate of scheduleEFields) {
      const existingField = await ctx.db
        .query("fields")
        .withIndex("by_instance", (q) => q.eq("instanceId", scheduleE!._id))
        .filter((q) => q.eq(q.field("fieldKey"), fieldUpdate.fieldKey))
        .first();
      
      if (existingField) {
        // Update existing field
        await ctx.db.patch(existingField._id, {
          value: fieldUpdate.value,
          isManualOverride: false,
          isCalculated: true,
        });
      } else {
        // Create new field
        await ctx.db.insert("fields", {
          instanceId: scheduleE!._id,
          fieldKey: fieldUpdate.fieldKey,
          value: fieldUpdate.value,
          isManualOverride: false,
          isCalculated: true,
        });
      }
    }
    
    // Also check for dividend income that goes to Form 1040 Schedule B
    if (k1Data.ordinaryDividends !== undefined || k1Data.qualifiedDividends !== undefined) {
      // Look for Schedule B or update 1040 directly
      // For simplicity, we'll track this in audit log
    }
    
    // Mark the K-1 as synced
    const now = Date.now();
    await ctx.db.patch(args.k1RecordId, {
      syncStatus: "synced",
      syncedAt: now,
    });
    
    // Log the sync in auditLogs with source "k1_sync" for audit trail
    await ctx.db.insert("auditLogs", {
      returnId: partnerReturnId as Id<"returns">,
      userId: args.userId,
      action: "K-1 Sync",
      previousValue: null,
      newValue: {
        k1RecordId: args.k1RecordId,
        businessReturnId: k1Record.returnId,
        k1Data,
        syncedAt: now,
      },
      source: "k1_sync",
      timestamp: now,
    });
    
    return {
      success: true,
      syncedAt: now,
      fieldsUpdated: scheduleEFields.length,
    };
  },
});

/**
 * Sync all pending K-1 records
 * 
 * This is typically run:
 * - After a business return is completed
 * - On a schedule (e.g., nightly sync)
 * - Manually by a preparer
 */
export const syncAllPendingK1s = internalMutation({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    // Get all pending K-1 records
    const pendingK1s = await ctx.db
      .query("k1Records")
      .withIndex("by_syncStatus", (q) => q.eq("syncStatus", "pending"))
      .collect();
    
    const results = {
      total: pendingK1s.length,
      succeeded: 0,
      failed: 0,
      errors: [] as string[],
    };
    
    for (const k1Record of pendingK1s) {
      try {
        // Get the K-1 record with latest data
        const k1 = await ctx.db.get(k1Record._id);
        if (!k1) {
          results.failed++;
          results.errors.push(`K-1 record not found: ${k1Record._id}`);
          continue;
        }
        
        // Skip if already synced (could have been synced by another process)
        if (k1.syncStatus === "synced") {
          results.succeeded++;
          continue;
        }
        
        // Sync the K-1 to the individual return
        const syncResult = await ctx.db.transaction(async (tx) => {
          // Get the K-1 record again within transaction
          const k1Data = k1.k1Data as K1Data;
          
          // Get the partner's individual return
          const partnerIdString = k1.partnerId as string;
          const individualReturn = await tx.get(partnerIdString as Id<"returns">);
          if (!individualReturn) {
            await tx.patch(k1._id, { syncStatus: "error" });
            return { success: false, error: "Partner return not found" };
          }
          
          // Find or create Schedule E
          let scheduleE = await tx
            .query("formInstances")
            .withIndex("by_return", (q) => q.eq("returnId", partnerIdString as Id<"returns">))
            .filter((q) => q.eq(q.field("formType"), "ScheduleE"))
            .first();
          
          if (!scheduleE) {
            const instanceId = await tx.insert("formInstances", {
              returnId: partnerIdString as Id<"returns">,
              formType: "ScheduleE",
              instanceName: "Schedule E - Supplemental Income",
              status: "In Progress",
              documentSource: "calculated",
            });
            scheduleE = await tx.get(instanceId);
          }
          
          // Map K-1 fields to Schedule E fields
          const updates: { fieldKey: string; value: any }[] = [];
          
          if (k1Data.ordinaryBusinessIncome !== undefined) {
            updates.push({ fieldKey: "line2_partnership", value: k1Data.ordinaryBusinessIncome });
          }
          if (k1Data.section199ADeduction !== undefined) {
            updates.push({ fieldKey: "line2_section199A", value: k1Data.section199ADeduction });
          }
          if (k1Data.charitableContributions !== undefined) {
            updates.push({ fieldKey: "line3_charitable", value: k1Data.charitableContributions });
          }
          
          // Apply updates
          for (const update of updates) {
            const existing = await tx
              .query("fields")
              .withIndex("by_instance", (q) => q.eq("instanceId", scheduleE!._id))
              .filter((q) => q.eq(q.field("fieldKey"), update.fieldKey))
              .first();
            
            if (existing) {
              await tx.patch(existing._id, {
                value: update.value,
                isManualOverride: false,
                isCalculated: true,
              });
            } else {
              await tx.insert("fields", {
                instanceId: scheduleE!._id,
                fieldKey: update.fieldKey,
                value: update.value,
                isManualOverride: false,
                isCalculated: true,
              });
            }
          }
          
          // Mark as synced
          const now = Date.now();
          await tx.patch(k1._id, {
            syncStatus: "synced",
            syncedAt: now,
          });
          
          // Log the sync
          await tx.insert("auditLogs", {
            returnId: partnerIdString as Id<"returns">,
            userId: args.userId,
            action: "K-1 Sync",
            previousValue: null,
            newValue: {
              k1RecordId: k1._id,
              businessReturnId: k1.returnId,
              syncedAt: now,
            },
            source: "k1_sync",
            timestamp: now,
          });
          
          return { success: true, syncedAt: now };
        });
        
        if (syncResult.success) {
          results.succeeded++;
        } else {
          results.failed++;
          results.errors.push(syncResult.error || "Unknown error");
        }
      } catch (error) {
        results.failed++;
        results.errors.push(`Error syncing K-1 ${k1Record._id}: ${error}`);
        
        // Mark as error
        await ctx.db.patch(k1Record._id, { syncStatus: "error" });
      }
    }
    
    return results;
  },
});

/**
 * Get audit trail for K-1 syncs for a return
 * 
 * Returns all K-1 sync events for a business return or individual return
 */
export const getK1AuditTrail = query({
  args: { returnId: v.id("returns") },
  handler: async (ctx, args) => {
    // Get K-1 records for this return
    const k1Records = await ctx.db
      .query("k1Records")
      .withIndex("by_return", (q) => q.eq("returnId", args.returnId))
      .collect();
    
    // Get audit logs for K-1 sync actions
    const auditLogs = await ctx.db
      .query("auditLogs")
      .withIndex("by_return", (q) => q.eq("returnId", args.returnId))
      .filter((q) => q.eq(q.field("action"), "K-1 Sync"))
      .order("desc")
      .take(100);
    
    return {
      k1Records: k1Records.map(k1 => ({
        id: k1._id,
        recipientName: k1.recipientName,
        syncStatus: k1.syncStatus,
        syncedAt: k1.syncedAt,
        createdAt: k1.createdAt,
      })),
      syncAuditLogs: auditLogs,
    };
  },
});

