/**
 * Seed sample K-1 data for testing
 * 
 * Usage: Import and call this function to create sample K-1 records
 */
export const seedSampleK1Data = mutation({
  args: { 
    businessReturnId: v.id("returns"),
    userId: v.string(),
  },
  handler: async (ctx, args) => {
    const createdIds: string[] = [];
    const now = Date.now();
    
    for (const sample of sampleK1Records) {
      const id = await ctx.db.insert("k1Records", {
        returnId: args.businessReturnId,
        partnerId: sample.partnerId,
        ein: sample.ein,
        recipientName: sample.recipientName,
        recipientTin: sample.recipientTin,
        k1Data: sample.k1Data,
        syncStatus: sample.syncStatus,
        createdAt: now,
      });
      
      createdIds.push(id);
    }
    
    // Log the seeding
    await ctx.db.insert("auditLogs", {
      returnId: args.businessReturnId,
      userId: args.userId,
      action: "K-1 Seed Data",
      previousValue: null,
      newValue: { count: createdIds.length },
      source: "system",
      timestamp: now,
    });
    
    return {
      success: true,
      createdCount: createdIds.length,
      k1RecordIds: createdIds,
    };
  },
});
